import{_ as e,o as a,c as t,ag as l}from"./chunks/framework.ByAj6Cie.js";const p=JSON.parse('{"title":"Conduit","description":"","frontmatter":{},"headers":[],"relativePath":"en/cables/installation/conduit.md","filePath":"en/cables/installation/conduit.md"}'),n={name:"en/cables/installation/conduit.md"};function o(r,i,s,c,d,u){return a(),t("div",null,[...i[0]||(i[0]=[l('<h1 id="conduit" tabindex="-1">Conduit <a class="header-anchor" href="#conduit" aria-label="Permalink to &quot;Conduit&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Conduit is a protective system used to route and safeguard electrical cables in industrial installations. It consists of tubes or channels that enclose cables, providing mechanical protection and environmental isolation.</p><p>Conduit is widely used in industrial environments where cables are exposed to physical damage, harsh conditions, or require organized routing.</p><hr><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>Conduit systems are used to:</p><ul><li>Protect cables from mechanical damage</li><li>Shield cables from environmental conditions (moisture, dust, chemicals)</li><li>Provide organized and structured cable routing</li><li>Improve safety by enclosing live conductors</li><li>Facilitate maintenance and future cable replacement</li></ul><hr><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>Cables are installed inside conduit pathways, which act as a physical barrier between the cable and its surroundings.</p><p>The conduit:</p><ul><li>Prevents direct exposure to external elements</li><li>Contains and organizes cable runs</li><li>Limits mechanical stress on cables</li></ul><p>However, enclosing cables also affects heat dissipation, which must be considered during cable sizing.</p><hr><h2 id="common-types-of-conduit" tabindex="-1">Common Types of Conduit <a class="header-anchor" href="#common-types-of-conduit" aria-label="Permalink to &quot;Common Types of Conduit&quot;">​</a></h2><h3 id="rigid-metal-conduit-rmc" tabindex="-1">Rigid Metal Conduit (RMC) <a class="header-anchor" href="#rigid-metal-conduit-rmc" aria-label="Permalink to &quot;Rigid Metal Conduit (RMC)&quot;">​</a></h3><ul><li>Made of steel or aluminum</li><li>High mechanical strength</li><li>Suitable for harsh environments</li></ul><p><strong>Applications:</strong></p><ul><li>Heavy industrial installations</li><li>Areas with high risk of impact</li></ul><hr><h3 id="electrical-metallic-tubing-emt" tabindex="-1">Electrical Metallic Tubing (EMT) <a class="header-anchor" href="#electrical-metallic-tubing-emt" aria-label="Permalink to &quot;Electrical Metallic Tubing (EMT)&quot;">​</a></h3><ul><li>Thin-wall metal conduit</li><li>Lighter and easier to install than RMC</li></ul><p><strong>Applications:</strong></p><ul><li>Indoor installations</li><li>Commercial and light industrial environments</li></ul><hr><h3 id="pvc-conduit" tabindex="-1">PVC Conduit <a class="header-anchor" href="#pvc-conduit" aria-label="Permalink to &quot;PVC Conduit&quot;">​</a></h3><ul><li>Non-metallic and corrosion-resistant</li><li>Lightweight and cost-effective</li></ul><p><strong>Applications:</strong></p><ul><li>Underground installations</li><li>Corrosive environments</li></ul><hr><h3 id="flexible-conduit" tabindex="-1">Flexible Conduit <a class="header-anchor" href="#flexible-conduit" aria-label="Permalink to &quot;Flexible Conduit&quot;">​</a></h3><ul><li>Made of flexible metal or plastic</li><li>Allows movement and vibration</li></ul><p><strong>Applications:</strong></p><ul><li>Connections to motors and moving equipment</li><li>Areas requiring flexibility</li></ul><hr><h2 id="applications" tabindex="-1">Applications <a class="header-anchor" href="#applications" aria-label="Permalink to &quot;Applications&quot;">​</a></h2><p>Conduit is used in:</p><ul><li>Industrial facilities and plants</li><li>Control panel wiring (external routing)</li><li>Outdoor and underground installations</li><li>Hazardous or corrosive environments</li></ul><hr><h2 id="key-considerations" tabindex="-1">Key Considerations <a class="header-anchor" href="#key-considerations" aria-label="Permalink to &quot;Key Considerations&quot;">​</a></h2><p>When selecting conduit:</p><ul><li><strong>Mechanical protection:</strong> required level of durability</li><li><strong>Environmental conditions:</strong> moisture, chemicals, temperature</li><li><strong>Flexibility needs:</strong> fixed vs moving installations</li><li><strong>Corrosion resistance:</strong> especially in harsh environments</li><li><strong>Installation complexity:</strong> ease of routing and assembly</li><li><strong>Heat dissipation:</strong> enclosed cables may require derating</li></ul><hr><h2 id="practical-notes" tabindex="-1">Practical Notes <a class="header-anchor" href="#practical-notes" aria-label="Permalink to &quot;Practical Notes&quot;">​</a></h2><ul><li>Conduit improves protection but reduces heat dissipation, which affects cable ampacity.</li><li>Overfilling conduit makes installation difficult and can cause overheating.</li><li>Proper sealing is important in outdoor or hazardous environments.</li><li>Flexible conduit should be used where vibration or movement is present.</li><li>Conduit systems should be planned to allow future expansion and maintenance.</li></ul>',46)])])}const m=e(n,[["render",o]]);export{p as __pageData,m as default};
